//조회완료
scwin.sbm_retrieve_submitdone = function (e) {
  console.log("scwin.sbm_retrieve_submitdone");
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  var rowCnt = ds_out.getTotalRow();
  if (rowCnt == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003, new Array("조회결과"));
    spn_totalRow.setValue(rowCnt);
  } else {
    ds_out.sort("odrNo", 1);
    //spn_totalRow.setValue(scwin.f_countSuppressCol("odrNo"));
    spn_totalRow.setValue(rowCnt);
    ds_out.setRowPosition(0);

    //중복컬럼 강제로 값 설정
    for (var i = 0; i < rowCnt; i++) {
      ds_out.setCellData(i, "bilgClntNo1", ds_out.getCellData(i, "bilgClntNo"));
      ds_out.setCellData(i, "bilgClntNn1", ds_out.getCellData(i, "bilgClntNn"));
    }
  }
};

