//조회조건 값 변경 > 오더기간/오더번호
scwin.lc_odrSearchGubun_onchange = function (info) {
  var v_index = lc_odrSearchGubun.getSelectedIndex();
  if (v_index == 0) {
    // 출발일자로 검색시 바인딩 정보 수정
    ed_odrNo.hide();
    udc_fromToCalendar.show("");

    // 오더기간, 출발일자 검색조건 초기화
    ed_odrDtFrom.setValue(scwin.strPreDate);
    ed_odrDtTo.setValue(scwin.strCurDate);
  } else {
    // 오더기간으로 검색시 바인딩 정보 수정
    ed_odrNo.show("");
    udc_fromToCalendar.hide();

    // 오더기간, 출발일자 검색조건 초기화
    ed_odrDtFrom.setValue(scwin.strPreDate);
    ed_odrDtTo.setValue(scwin.strCurDate);
  }
};

